{"content":"868: /* static */
869: nsresult EventDispatcher::Dispatch(EventTarget* aTarget,
870:                                    nsPresContext* aPresContext,
871:                                    WidgetEvent* aEvent, Event* aDOMEvent,
872:                                    nsEventStatus* aEventStatus,
873:                                    EventDispatchingCallback* aCallback,
874:                                    nsTArray<EventTarget*>* aTargets) {
875:   AUTO_PROFILER_LABEL_HOT("EventDispatcher::Dispatch", OTHER);
876: 
877:   NS_ASSERTION(aEvent, "Trying to dispatch without WidgetEvent!");
878:   NS_ENSURE_TRUE(!aEvent->mFlags.mIsBeingDispatched,
879:                  NS_ERROR_DOM_INVALID_STATE_ERR);
880:   NS_ASSERTION(!aTargets || !aEvent->mMessage, "Wrong parameters!");
881: 
882:   // If we're dispatching an already created DOMEvent object, make
883:   // sure it is initialized!
884:   // If aTargets is non-null, the event isn't going to be dispatched.
885:   NS_ENSURE_TRUE(aEvent->mMessage || !aDOMEvent || aTargets,
886:                  NS_ERROR_DOM_INVALID_STATE_ERR);
887: 
888:   // Events shall not be fired while we are in stable state to prevent anything
889:   // visible from the scripts.
890:   MOZ_ASSERT(!nsContentUtils::IsInStableOrMetaStableState());
891:   NS_ENSURE_TRUE(!nsContentUtils::IsInStableOrMetaStableState(),
892:                  NS_ERROR_DOM_INVALID_STATE_ERR);
893: 
894:   nsCOMPtr<EventTarget> target(aTarget);
895: 
896:   RefPtr<PerformanceEventTiming> eventTimingEntry;
897:   // Similar to PerformancePaintTiming, we don't need to
898:   // expose them for printing documents
899:   if (aPresContext && !aPresContext->IsPrintingOrPrintPreview()) {
900:     eventTimingEntry =
901:         PerformanceEventTiming::TryGenerateEventTiming(target, aEvent);
902: 
903:     if (aEvent->IsTrusted() && aEvent->mMessage == eScroll) {
904:       if (auto* perf = aPresContext->GetPerformanceMainThread()) {
905:         if (!perf->HasDispatchedScrollEvent()) {
906:           perf->SetHasDispatchedScrollEvent();
907:         }
908:       }
909:     }
910:   }
911: 
912:   bool retargeted = false;
913: 
914:   if (aEvent->mFlags.mRetargetToNonNativeAnonymous) {
915:     nsIContent* content = nsIContent::FromEventTargetOrNull(target);
916:     if (content && content->IsInNativeAnonymousSubtree()) {
917:       nsCOMPtr<EventTarget> newTarget =
918:           content->FindFirstNonChromeOnlyAccessContent();
919:       NS_ENSURE_STATE(newTarget);
920: 
921:       aEvent->mOriginalTarget = target;
922:       target = newTarget;
923:       retargeted = true;
924:     }
925:   }
926: 
927:   if (aEvent->mFlags.mOnlyChromeDispatch) {
928:     nsCOMPtr<Document> doc;
929:     if (!IsEventTargetChrome(target, getter_AddRefs(doc)) && doc) {
930:       nsPIDOMWindowInner* win = doc->GetInnerWindow();
931:       // If we can't dispatch the event to chrome, do nothing.
932:       EventTarget* piTarget = win ? win->GetParentTarget() : nullptr;
933:       if (!piTarget) {
934:         return NS_OK;
935:       }
936: 
937:       // Set the target to be the original dispatch target,
938:       aEvent->mTarget = target;
939:       // but use chrome event handler or BrowserChildMessageManager for event
940:       // target chain.
941:       target = piTarget;
942:     } else if (NS_WARN_IF(!doc)) {
943:       return NS_ERROR_UNEXPECTED;
944:     }
945:   }
946: 
947: #ifdef DEBUG
948:   if (NS_IsMainThread() && aEvent->mMessage != eVoidEvent &&
949:       !nsContentUtils::IsSafeToRunScript()) {
950:     static const auto warn = [](bool aIsSystem) {
951:       if (aIsSystem) {
952:         NS_WARNING("Fix the caller!");
953:       } else {
954:         MOZ_CRASH("This is unsafe! Fix the caller!");
955:       }
956:     };
957:     if (nsINode* node = nsINode::FromEventTargetOrNull(target)) {
958:       // If this is a node, it's possible that this is some sort of DOM tree
959:       // that is never accessed by script (for example an SVG image or XBL
960:       // binding document or whatnot).  We really only want to warn/assert here
961:       // if there might be actual scripted listeners for this event, so restrict
962:       // the warnings/asserts to the case when script can or once could touch
963:       // this node's document.
964:       Document* doc = node->OwnerDoc();
965:       bool hasHadScriptHandlingObject;
966:       nsIGlobalObject* global =
967:           doc->GetScriptHandlingObject(hasHadScriptHandlingObject);
968:       if (global || hasHadScriptHandlingObject) {
969:         warn(nsContentUtils::IsChromeDoc(doc));
970:       }
971:     } else if (nsCOMPtr<nsIGlobalObject> global = target->GetOwnerGlobal()) {
972:       warn(global->PrincipalOrNull()->IsSystemPrincipal());
973:     }
974:   }
975: 
976:   if (aDOMEvent) {
977:     WidgetEvent* innerEvent = aDOMEvent->WidgetEventPtr();
978:     NS_ASSERTION(innerEvent == aEvent,
979:                  "The inner event of aDOMEvent is not the same as aEvent!");
980:   }
981: #endif
982: 
983:   nsresult rv = NS_OK;
984:   bool externalDOMEvent = !!(aDOMEvent);
985: 
986:   // If we have a PresContext, make sure it doesn't die before
987:   // event dispatching is finished.
988:   RefPtr<nsPresContext> kungFuDeathGrip(aPresContext);
989: 
990:   ELMCreationDetector cd;
991:   nsTArray<EventTargetChainItem> chain;
992:   if (cd.IsMainThread()) {
993:     if (!sCachedMainThreadChains) {
994:       sCachedMainThreadChains = new CachedChains();
995:     }
996: 
997:     if (sCachedMainThreadChains->mChain1.Capacity() ==
998:         kCachedMainThreadChainSize) {
999:       chain = std::move(sCachedMainThreadChains->mChain1);
1000:     } else if (sCachedMainThreadChains->mChain2.Capacity() ==
1001:                kCachedMainThreadChainSize) {
1002:       chain = std::move(sCachedMainThreadChains->mChain2);
1003:     } else {
1004:       chain.SetCapacity(kCachedMainThreadChainSize);
1005:     }
1006:   }
1007: 
1008:   // Create the event target chain item for the event target.
1009:   EventTargetChainItem* targetEtci = EventTargetChainItem::Create(
1010:       chain, target->GetTargetForEventTargetChain());
1011:   MOZ_ASSERT(&chain[0] == targetEtci);
1012:   if (!targetEtci->IsValid()) {
1013:     EventTargetChainItem::DestroyLast(chain, targetEtci);
1014:     return NS_ERROR_FAILURE;
1015:   }
1016: 
1017:   // Make sure that Event::target and Event::originalTarget
1018:   // point to the last item in the chain.
1019:   if (!aEvent->mTarget) {
1020:     // Note, CurrentTarget() points always to the object returned by
1021:     // GetTargetForEventTargetChain().
1022:     aEvent->mTarget = targetEtci->CurrentTarget();
1023:   } else {
1024:     // XXX But if the target is already set, use that. This is a hack
1025:     //     for the 'load', 'beforeunload' and 'unload' events,
1026:     //     which are dispatched to |window| but have document as their target.
1027:     //
1028:     // Make sure that the event target points to the right object.
1029:     aEvent->mTarget = aEvent->mTarget->GetTargetForEventTargetChain();
1030:     NS_ENSURE_STATE(aEvent->mTarget);
1031:   }
1032: 
1033:   if (retargeted) {
1034:     aEvent->mOriginalTarget =
1035:         aEvent->mOriginalTarget->GetTargetForEventTargetChain();
1036:     NS_ENSURE_STATE(aEvent->mOriginalTarget);
1037:   } else {
1038:     aEvent->mOriginalTarget = aEvent->mTarget;
1039:   }
1040: 
1041:   aEvent->mOriginalRelatedTarget = aEvent->mRelatedTarget;
1042: 
1043:   bool clearTargets = false;
1044: 
1045:   nsCOMPtr<nsIContent> content =
1046:       nsIContent::FromEventTargetOrNull(aEvent->mOriginalTarget);
1047: 
1048:   const bool isInAnon = content && content->ChromeOnlyAccessForEvents();
1049:   aEvent->mFlags.mIsBeingDispatched = true;
1050: 
1051: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/firefox--871325b8@01dcdcebaca08ed5c32f8d50532752a063dc5ade/-/blob/dom/events/EventDispatcher.cpp%3FL868-1050"}

{"content":"1379: /* static */
1380: nsresult EventDispatcher::DispatchDOMEvent(EventTarget* aTarget,
1381:                                            WidgetEvent* aEvent,
1382:                                            Event* aDOMEvent,
1383:                                            nsPresContext* aPresContext,
1384:                                            nsEventStatus* aEventStatus) {
1385:   if (aDOMEvent) {
1386:     WidgetEvent* innerEvent = aDOMEvent->WidgetEventPtr();
1387:     NS_ENSURE_TRUE(innerEvent, NS_ERROR_ILLEGAL_VALUE);
1388: 
1389:     // Don't modify the event if it's being dispatched right now.
1390:     if (innerEvent->mFlags.mIsBeingDispatched) {
1391:       return NS_ERROR_DOM_INVALID_STATE_ERR;
1392:     }
1393: 
1394:     bool dontResetTrusted = false;
1395:     if (innerEvent->mFlags.mDispatchedAtLeastOnce) {
1396:       innerEvent->mTarget = nullptr;
1397:       innerEvent->mOriginalTarget = nullptr;
1398:     } else {
1399:       dontResetTrusted = aDOMEvent->IsTrusted();
1400:     }
1401: 
1402:     if (!dontResetTrusted) {
1403:       // Check security state to determine if dispatcher is trusted
1404:       bool trusted = NS_IsMainThread()
1405:                          ? nsContentUtils::LegacyIsCallerChromeOrNativeCode()
1406:                          : IsCurrentThreadRunningChromeWorker();
1407:       aDOMEvent->SetTrusted(trusted);
1408:     }
1409: 
1410:     return EventDispatcher::Dispatch(aTarget, aPresContext, innerEvent,
1411:                                      aDOMEvent, aEventStatus);
1412:   } else if (aEvent) {
1413:     return EventDispatcher::Dispatch(aTarget, aPresContext, aEvent, aDOMEvent,
1414:                                      aEventStatus);
1415:   }
1416:   return NS_ERROR_ILLEGAL_VALUE;
1417: }
