1419: /* static */ already_AddRefed<dom::Event> EventDispatcher::CreateEvent(
1420:     EventTarget* aOwner, nsPresContext* aPresContext, WidgetEvent* aEvent,
1421:     const nsAString& aEventType, CallerType aCallerType) {
1422:   if (aEvent) {
1423:     switch (aEvent->mClass) {
1424:       case eGUIEventClass:
1425:       case eScrollPortEventClass:
1426:       case eUIEventClass:
1427:         return NS_NewDOMUIEvent(aOwner, aPresContext, aEvent->AsGUIEvent());
1428:       case eScrollAreaEventClass:
