1469:   RefPtr<nsAtom> typeAtom = nsContentUtils::GetEventType(aEvent);
1470:   if (!typeAtom) {
1471:     // Some messages don't have a corresponding type atom, e.g.
1472:     // eMouseEnterIntoWidget. These events can't have a listener, so we
1473:     // can stop here.
