1500:     // If we didn't find any matching listeners, and our event has a legacy
1501:     // version, check the listeners for the legacy version.
1502:     EventMessage legacyEventMessage = GetLegacyEventMessage(eventMessage);
1503:     if (legacyEventMessage != eventMessage) {
1504:       MOZ_ASSERT(
1505:           GetLegacyEventMessage(legacyEventMessage) == legacyEventMessage,
1506:           "Legacy event messages should not themselves have legacy versions");
1507:       RefPtr<nsAtom> legacyTypeAtom =
1508:           nsContentUtils::GetEventTypeFromMessage(legacyEventMessage);
1509:       if (RefPtr<ListenerArray> legacyListeners =
1510:               mListenerMap.GetListenersForType(legacyTypeAtom)) {
1511:         HandleEventWithListenerArray(
1512:             legacyListeners, legacyTypeAtom, legacyEventMessage, aPresContext,
1513:             aEvent, aDOMEvent, aCurrentTarget, aItemInShadowTree);
1514:         hasAnyListenerForEventType = true;
1515:       }
1516:     }
1517:   }
1518: 
1519:   aEvent->mCurrentTarget = nullptr;
1520: 
1521:   if (mIsMainThreadELM && !hasAnyListenerForEventType) {
1522:     if (aEvent->mMessage != eUnidentifiedEvent) {
1523:       mNoListenerForEvents[2] = mNoListenerForEvents[1];
1524:       mNoListenerForEvents[1] = mNoListenerForEvents[0];
1525:       mNoListenerForEvents[0] = aEvent->mMessage;
1526:     } else {
1527:       mNoListenerForEventAtom = aEvent->mSpecifiedEventType;
1528:     }
1529:   }
1530: 
1531:   if (aEvent->DefaultPrevented()) {
1532:     *aEventStatus = nsEventStatus_eConsumeNoDefault;
1533:   }
1534: }
