1536: bool EventListenerManager::HandleEventWithListenerArray(
1537:     ListenerArray* aListeners, nsAtom* aTypeAtom, EventMessage aEventMessage,
1538:     nsPresContext* aPresContext, WidgetEvent* aEvent, Event** aDOMEvent,
1539:     EventTarget* aCurrentTarget, bool aItemInShadowTree) {
1540:   auto ensureDOMEvent = [&]() {
1541:     if (!*aDOMEvent) {
1542:       // Lazily create the DOM event.
1543:       // This is tiny bit slow, but happens only once per event.
1544:       // Similar code also in EventDispatcher.
1545:       nsCOMPtr<EventTarget> et = aEvent->mOriginalTarget;
1546:       RefPtr<Event> event =
1547:           EventDispatcher::CreateEvent(et, aPresContext, aEvent, u""_ns);
1548:       event.forget(aDOMEvent);
1549:     }
1550:     return *aDOMEvent != nullptr;
1551:   };
1552: 
1553:   Maybe<EventMessageAutoOverride> eventMessageAutoOverride;
1554:   bool isOverridingEventMessage = aEvent->mMessage != aEventMessage;
1555:   bool hasAnyListenerMatchingGroup = false;
1556:   bool didReplaceOnceListener = false;
1557: 
1558:   for (Listener& listenerRef : aListeners->EndLimitedRange()) {
1559:     Listener* listener = &listenerRef;
1560:     if (!ListenerCanHandle(listener, aEvent)) {
1561:       continue;
1562:     }
1563:     hasAnyListenerMatchingGroup = true;
1564: 
1565:     // Check that the phase is same in event and event listener. Also check
1566:     // that the event is trusted or that the listener allows untrusted events.
1567:     if (!listener->MatchesEventPhase(aEvent) ||
1568:         !listener->AllowsEventTrustedness(aEvent)) {
1569:       continue;
1570:     }
1571: 
1572:     Maybe<Listener> listenerHolder;
1573:     if (listener->mFlags.mOnce) {
1574:       // Move the listener to the stack before handling the event.
1575:       // The order is important, otherwise the listener could be
1576:       // called again inside the listener.
1577:       listenerHolder.emplace(std::move(*listener));
1578:       listener = listenerHolder.ptr();
1579:       didReplaceOnceListener = true;
1580:     }
1581:     if (ensureDOMEvent()) {
1582:       if (isOverridingEventMessage && !eventMessageAutoOverride) {
1583:         // Override the domEvent's event-message (its .type) until we
1584:         // finish traversing listeners (when eventMessageAutoOverride
1585:         // destructs).
1586:         eventMessageAutoOverride.emplace(*aDOMEvent, aEventMessage);
1587:       }
1588:       if (!HandleEventSingleListener(listener, aTypeAtom, aEvent, *aDOMEvent,
1589:                                      aCurrentTarget, aItemInShadowTree)) {
1590:         break;
1591:       }
1592:     }
1593:   }
1594: 
1595:   if (didReplaceOnceListener) {
1596:     // If there are any once listeners replaced with a placeholder during the
1597:     // loop above, we need to clean up them here. Note that this could clear
1598:     // once listeners handled in some outer level as well, but that should not
1599:     // affect the result.
1600:     size_t oldLength = aListeners->Length();
1601:     aListeners->NonObservingRemoveElementsBy([](const Listener& aListener) {
1602:       return aListener.mListenerType == Listener::eNoListener;
1603:     });
1604:     size_t newLength = aListeners->Length();
1605:     if (newLength == 0) {
1606:       // Remove the entry that has now become empty.
1607:       mListenerMap.mEntries.RemoveElementsBy([](EventListenerMapEntry& entry) {
1608:         return entry.mListeners->IsEmpty();
1609:       });
1610:     }
1611:     if (newLength < oldLength) {
1612:       // Call NotifyEventListenerRemoved once for every removed listener.
1613:       size_t removedCount = oldLength - newLength;
1614:       for (size_t i = 0; i < removedCount; i++) {
1615:         NotifyEventListenerRemoved(aTypeAtom);
1616:       }
1617:       if (IsDeviceType(aTypeAtom)) {
1618:         // Call DisableDevice once for every removed listener.
1619:         for (size_t i = 0; i < removedCount; i++) {
1620:           DisableDevice(aTypeAtom);
1621:         }
1622:       }
1623:     }
1624:   }
1625: 
1626:   return hasAnyListenerMatchingGroup;
1627: }
